import redis

def execute_lua_script():
    # Connect to Redis server
    r = redis.StrictRedis(host='localhost', port=6379, db=0)

    # Accept Lua script code from user input
    lua_script = input("Enter the Lua script code: ")

    # Compile the Lua script
    sha = r.script_load(lua_script)

    # Get parameters from user
    num_args = int(input("Number of arguments for the script: "))
    args = []
    for i in range(num_args):
        arg = input(f"Argument {i+1}: ")
        args.append(arg)

    # Execute the Lua script with user-provided arguments
    result = r.evalsha(sha, len(args), *args)

    print("Script executed successfully. Result:")
    print(result)

if __name__ == "__main__":
    execute_lua_script()